ValidationRule.errorConditionFormula:
AND(
    NOT(
        OR(
            AND(
                NOT(ISBLANK(TEXT( InquiryType1__c ))),
                NOT(ISBLANK( Date1__c )),
                LEN ( URL1__c ) > 0
            ),
            AND(
                ISBLANK(TEXT( InquiryType1__c )),
                ISBLANK( Date1__c ),
                 LEN ( URL1__c ) = 0
            )
        )
    ),
    NOT(
        OR(
            $Profile.Name = 'システム管理者',
            $Profile.Name = 'データ移行管理者'
        )
    )
)
